const { WorkOS } = require('@workos-inc/node');
const fs = require('fs');

const workos = new WorkOS(process.env.WORKOS_API_KEY);

async function setup() {
  try {
    // 1. Create Organization
    console.log('Creating organization...');
    const org = await workos.organizations.createOrganization({ name: 'FGA Test Organization' });
    const organizationId = org.id;

    // 2. Create Permissions
    console.log('Creating permissions...');
    const editorPermission = await workos.authorization.createPermission({
      slug: 'editor',
      name: 'Editor Permission',
    }).catch(e => {
        if (e.status === 409) return { slug: 'editor' };
        throw e;
    });
    const viewerPermission = await workos.authorization.createPermission({
      slug: 'viewer',
