    results.push({
      check: 'user_bob has editor access to doc_123',
      result: bobEditorCheck.authorized
    });

    // 3. Check if user_bob has viewer access to doc_123
    console.log('Checking Bob viewer access to doc_123...');
    const bobViewerCheck = await workos.authorization.check({
      organizationMembershipId: ids.omBobId,
      permissionSlug: 'viewer',
      resourceId: ids.docId,
    });
    results.push({
